index.js.content:
import http from "node:http";

import { run } from "@grammyjs/runner";
import { cfg } from "./lib/config.js";
import { safeErr } from "./lib/safeErr.js";
import { getDb } from "./lib/db.js";
import { buildBot } from "./bot.js";
import { getLastError, parseAdminIds, setLastError } from "./lib/runtime.js";

process.on("unhandledRejection", (e) => {
  console.error("[process] unhandledRejection", { err: safeErr(e) });
  process.exit(1);
});
process.on("uncaughtException", (e) => {
  console.error("[process] uncaughtException", { err: safeErr(e) });
  process.exit(1);
});

async function sleep(ms) {
  await new Promise((r) => setTimeout(r, ms));
}

let pollRunner = null;
let restartLock = false;

function startHeartbeat() {
  const intervalMs = Number(process.env.HEARTBEAT_MS || 60_000);
  if (!Number.isFinite(intervalMs) || intervalMs <= 0) return;

  setInterval(() => {
    const m = process.memoryUsage();
    console.log("[heartbeat]", {
      uptimeS: Math.floor(process.uptime()),
      rssMB: Math.round(m.rss / 1e6),
      heapUsedMB: Math.round(m.heapUsed / 1e6),
    });
  }, intervalMs).unref();
}

async function maybeStartWebhookServer() {
  const port = Number(process.env.PORT || 0);
  if (!port) return { server: null, listening: false, port: 0 };

  const server = http.createServer((req, res) => {
    // This project primarily uses long polling.
    // If a webhook is configured in the future, this server can be extended to receive updates.
    res.statusCode = 200;
    res.setHeader("Content-Type", "text/plain");
    res.end("ok");
  });

  await new Promise((resolve) => server.listen(port, resolve));
  console.log("[http] listening", { port });

  return { server, listening: true, port };
}

async function startPolling(bot, runtimeInfo) {
  let backoffMs = 2000;

  for (;;) {
    try {
      console.log("[polling] starting", { concurrency: 1 });

      // Use runner for stable long polling.
      // Concurrency is kept at 1 to avoid runaway backlog/memory.
      pollRunner = run(bot, { concurrency: 1 });

      runtimeInfo.updateMode = "polling";

      // Small periodic log so we can see it's alive even when idle
      let lastLog = Date.now();
      const tick = setInterval(() => {
        const now = Date.now();
        if (now - lastLog > 60_000) {
          console.log("[polling] alive");
          lastLog = now;
        }
      }, 30_000);
      tick.unref();

      await pollRunner.task();

      console.warn("[polling] runner stopped (will restart)");
    } catch (e) {
      const msg = safeErr(e);
      setLastError(e);
      console.error("[polling] error", { err: msg });

      // Telegram conflict (another instance polling, or webhook set)
      if (/409|Conflict/i.test(msg)) {
        console.warn("[polling] conflict detected", {
          hint: "Another instance may be running, or a webhook is set. Will backoff and retry.",
          backoffMs,
        });

        try {
          // Safe remediation: clear webhook before polling
          await bot.api.deleteWebhook({ drop_pending_updates: true });
          console.log("[polling] deleteWebhook ok");
        } catch (e2) {
          console.warn("[polling] deleteWebhook failed", { err: safeErr(e2) });
        }
      }

      await sleep(backoffMs);
      backoffMs = Math.min(20_000, Math.round(backoffMs * 1.8));
    } finally {
      try {
        pollRunner?.abort?.();
      } catch {}
      pollRunner = null;
    }
  }
}

async function boot() {
  const adminIds = parseAdminIds(process.env.ADMIN_TELEGRAM_USER_IDS);
  const webhookUrl = String(process.env.TELEGRAM_WEBHOOK_URL || "").trim();

  const runtimeInfo = {
    updateMode: "unknown",
    telegramTokenSet: Boolean(cfg.TELEGRAM_BOT_TOKEN),
    dbConnected: false,
    aiEnabled: Boolean(process.env.COOKMYBOTS_AI_ENDPOINT) && Boolean(process.env.COOKMYBOTS_AI_KEY),
    lastError: "",
  };

  console.log("[boot]", {
    nodeEnv: process.env.NODE_ENV || "",
    telegramTokenSet: Boolean(cfg.TELEGRAM_BOT_TOKEN),
    mongodbUriSet: Boolean(process.env.MONGODB_URI),
    cookmybotsAiEndpointSet: Boolean(process.env.COOKMYBOTS_AI_ENDPOINT),
    cookmybotsAiKeySet: Boolean(process.env.COOKMYBOTS_AI_KEY),
    webhookUrlSet: Boolean(webhookUrl),
    portSet: Boolean(process.env.PORT),
    adminIdsConfigured: adminIds.length > 0,
  });

  if (!cfg.TELEGRAM_BOT_TOKEN) {
    console.error("TELEGRAM_BOT_TOKEN is required. Set it in your environment (or .env for local dev).");
    process.exit(1);
  }

  startHeartbeat();

  // DB is optional; never block bot boot on DB issues.
  if (process.env.MONGODB_URI) {
    try {
      const db = await getDb(process.env.MONGODB_URI);
      runtimeInfo.dbConnected = Boolean(db);
      console.log("[db] connect ok", { connected: runtimeInfo.dbConnected });
    } catch (e) {
      setLastError(e);
      console.warn("[db] connect failed", { err: safeErr(e) });
      runtimeInfo.dbConnected = false;
    }
  } else {
    console.warn("[db] disabled (MONGODB_URI not set)");
  }

  const { listening } = await maybeStartWebhookServer();

  // Decide update mode.
  // Prefer polling unless webhook is explicitly configured AND an HTTP port is listening.
  const webhookReady = Boolean(webhookUrl) && Boolean(listening);

  const bot = await buildBot({ token: cfg.TELEGRAM_BOT_TOKEN, runtimeInfo, adminIds });

  // Ensure bot.init + set commands are not fatal
  try {
    await bot.init();
    console.log("[tg] bot.init ok", { username: bot.botInfo?.username || "" });
  } catch (e) {
    setLastError(e);
    console.warn("[tg] bot.init failed (continuing)", { err: safeErr(e) });
  }

  try {
    await bot.api.setMyCommands([
      { command: "start", description: "Welcome and examples" },
      { command: "help", description: "Supported links and troubleshooting" },
    ]);
  } catch (e) {
    setLastError(e);
    console.warn("[tg] setMyCommands failed (continuing)", { err: safeErr(e) });
  }

  if (!webhookReady) {
    if (webhookUrl && !listening) {
      console.warn("[webhook] TELEGRAM_WEBHOOK_URL is set but PORT is not listening; falling back to polling");
    } else {
      console.log("[webhook] not configured; using polling");
    }

    // Always clear webhook when polling to avoid conflicts
    try {
      await bot.api.deleteWebhook({ drop_pending_updates: true });
      console.log("[tg] deleteWebhook ok");
    } catch (e) {
      setLastError(e);
      console.warn("[tg] deleteWebhook failed (continuing)", { err: safeErr(e) });
    }

    // Keep runtimeInfo updated for /health
    setInterval(() => {
      runtimeInfo.lastError = getLastError();
    }, 5000).unref();

    await startPolling(bot, runtimeInfo);
    return;
  }

  // Webhook mode placeholder: not enabled in this project by default.
  // We log and then still fall back to polling so the bot always works.
  console.warn("[webhook] webhook mode is not implemented in this bot. Falling back to polling.");

  try {
    await bot.api.deleteWebhook({ drop_pending_updates: true });
  } catch {}

  setInterval(() => {
    runtimeInfo.lastError = getLastError();
  }, 5000).unref();

  await startPolling(bot, runtimeInfo);
}

boot().catch((e) => {
  console.error("[boot] fatal", { err: safeErr(e) });
  process.exit(1);
});

ai.js.content:
function trimSlash(u) {
  u = String(u || "");
  while (u.endsWith("/")) u = u.slice(0, -1);
  return u;
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function safeRead(r) {
  const text = await r.text();
  let json = null;
  try {
    json = JSON.parse(text);
  } catch {}
  return { text, json };
}

function notConfigured(message) {
  return { ok: false, status: 412, json: null, text: "", error: message };
}

function withTimeout(ms) {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), ms);
  return { ctrl, clear: () => clearTimeout(t) };
}

function pickTimeout(cfg) {
  const v = Number(cfg?.AI_TIMEOUT_MS || cfg?.AI_TIMEOUT || 20000);
  return Number.isFinite(v) && v > 0 ? v : 20000;
}

function pickModel(cfg, override) {
  const m = String(override || cfg?.AI_MODEL || "").trim();
  return m || undefined;
}

function isRetryableStatus(status) {
  // 408: request timeout, 429: rate, 500/502/503/504 transient
  return (
    status === 408 ||
    status === 429 ||
    status === 500 ||
    status === 502 ||
    status === 503 ||
    status === 504
  );
}

function redact(s) {
  s = String(s || "");
  if (s.length <= 400) return s;
  return s.slice(0, 400) + "…";
}

function web3Mode(cfg) {
  const m = String(cfg?.WEB3_CHAT_MODE || "auto").trim().toLowerCase();
  return m === "on" || m === "off" || m === "auto" ? m : "auto";
}

async function aiGet(cfg, path, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  const DEBUG = String(cfg?.AI_DEBUG || "") === "1";
  if (!base || !key)
    return notConfigured(
      "AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)"
    );

  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const url = base + String(path || "");

  const { ctrl, clear } = withTimeout(timeoutMs);
  try {
    if (DEBUG) console.log("[aiGet] ->", url);
    const r = await fetch(url, {
      method: "GET",
      headers: { Authorization: "Bearer " + key },
      signal: ctrl.signal,
    });
    const { text, json } = await safeRead(r);
    if (!r.ok) {
      const err = json?.error || json?.message || text || "AI_ERROR";
      return { ok: false, status: r.status, json, text, error: String(err) };
    }
    return { ok: true, status: r.status, json, text, error: null };
  } catch (e) {
    const msg =
      e?.name === "AbortError" ? "AI_TIMEOUT" : e?.message || "AI_NETWORK_ERROR";
    return {
      ok: false,
      status: e?.name === "AbortError" ? 408 : 0,
      json: null,
      text: "",
      error: String(msg),
    };
  } finally {
    clear();
  }
}

async function routeChat(cfg, userText, systemHint) {
  // Uses the normal gateway /chat as a fast classifier.
  // Returns: "web3" | "normal"
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  if (!base || !key) return "normal";

  const timeoutMs = Math.min(8000, pickTimeout(cfg));
  const { ctrl, clear } = withTimeout(timeoutMs);

  const sys = [
    "You are a routing classifier for a bot.",
    "Decide if the user's message should go to a Web3 specialist model (ChainGPT) or a normal general AI model.",
    "",
    "Return ONLY valid JSON:",
    '{"route":"web3"}',
    "or",
    '{"route":"normal"}',
    "",
    "Route to web3 if the user asks about: crypto, tokens, Solidity, smart contracts, audits, DeFi, NFTs, wallets, chains, bridges, gas, DEXs, on-chain tools or anything related to blockchain.",
    "Otherwise route to normal.",
    "",
    "Extra context (bot/system hint):",
    String(systemHint || "").slice(0, 800),
  ].join("\n");

  try {
    const r = await fetch(base + "/chat", {
      method: "POST",
      headers: {
        Authorization: "Bearer " + key,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        messages: [
          { role: "system", content: sys },
          { role: "user", content: String(userText || "").slice(0, 2000) },
        ],
        model: pickModel(cfg, ""),
      }),
      signal: ctrl.signal,
    });

    const { text, json } = await safeRead(r);

    if (!r.ok) return "normal";

    // Accept either gateway's raw json or a wrapped assistant response.
    const raw = json || (text ? (() => {
      try {
        return JSON.parse(text);
      } catch {
        return null;
      }
    })() : null);

    const route =
      raw?.route ||
      raw?.json?.route ||
      raw?.data?.route ||
      raw?.result?.route ||
      raw?.message?.route;

    return route === "web3" ? "web3" : "normal";
  } catch {
    return "normal";
  } finally {
    clear();
  }
}

async function aiCall(cfg, path, payload, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  const DEBUG = String(cfg?.AI_DEBUG || "") === "1";

  if (!base || !key)
    return notConfigured(
      "AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)"
    );

  const retries = Number.isFinite(Number(opts.retries)) ? Number(opts.retries) : 1;
  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const url = base + String(path || "");

  let attempt = 0;
  while (attempt <= retries) {
    attempt++;

    const { ctrl, clear } = withTimeout(timeoutMs);
    try {
      if (DEBUG) console.log("[aiCall] ->", url, "attempt", attempt);

      const r = await fetch(url, {
        method: "POST",
        headers: {
          Authorization: "Bearer " + key,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload || {}),
        signal: ctrl.signal,
      });

      const { text, json } = await safeRead(r);

      if (!r.ok) {
        const err = json?.error || json?.message || text || "AI_ERROR";
        if (DEBUG)
          console.warn(
            "[aiCall] failed:",
            r.status,
            "attempt",
            attempt,
            redact(err)
          );

        if (attempt <= retries && isRetryableStatus(r.status)) {
          await sleep(250 * attempt);
          continue;
        }

        return { ok: false, status: r.status, json, text, error: String(err) };
      }

      if (DEBUG) console.log("[aiCall] ok:", r.status);
      return { ok: true, status: r.status, json, text, error: null };
    } catch (e) {
      const msg =
        e?.name === "AbortError" ? "AI_TIMEOUT" : e?.message || "AI_NETWORK_ERROR";
      if (DEBUG)
        console.warn("[aiCall] exception:", "attempt", attempt, redact(msg));

      const status = e?.name === "AbortError" ? 408 : 0;
      if (attempt <= retries && (status === 408 || status === 0)) {
        await sleep(250 * attempt);
        continue;
      }

      return { ok: false, status, json: null, text: "", error: String(msg) };
    } finally {
      clear();
    }
  }

  return { ok: false, status: 500, json: null, text: "", error: "AI_RETRY_EXHAUSTED" };
}

export async function aiChat(cfg, userText, { system = "", meta = {}, retries = 1 } = {}) {
  return aiCall(
    cfg,
    "/chat",
    {
      messages: [
        { role: "system", content: String(system || "") },
        { role: "user", content: String(userText || "") },
      ],
      meta: meta || undefined,
      model: pickModel(cfg, ""),
    },
    { retries }
  );
}

export async function aiVideoStart(cfg, { prompt, meta } = {}, opts = {}) {
  return aiCall(
    cfg,
    "/video",
    {
      prompt: String(prompt || ""),
      meta: meta || undefined,
      model: pickModel(cfg, ""),
    },
    opts
  );
}

export async function aiVideoStatus(cfg, jobId, opts = {}) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  const key = String(cfg?.COOKMYBOTS_AI_KEY || "");
  const DEBUG = String(cfg?.AI_DEBUG || "") === "1";

  if (!base || !key)
    return notConfigured(
      "AI_NOT_CONFIGURED (missing COOKMYBOTS_AI_ENDPOINT/COOKMYBOTS_AI_KEY)"
    );

  const timeoutMs = Number(opts.timeoutMs || pickTimeout(cfg));
  const url = base + "/video/" + encodeURIComponent(String(jobId || ""));

  const { ctrl, clear } = withTimeout(timeoutMs);
  try {
    if (DEBUG) console.log("[aiVideoStatus] ->", url);

    const r = await fetch(url, {
      headers: { Authorization: "Bearer " + key },
      signal: ctrl.signal,
    });

    const { text, json } = await safeRead(r);

    if (!r.ok) {
      const err = json?.error || json?.message || text || "AI_VIDEO_STATUS_ERROR";
      if (DEBUG) console.warn("[aiVideoStatus] failed:", r.status, redact(err));
      return { ok: false, status: r.status, json, text, error: String(err) };
    }

    return { ok: true, status: r.status, json, text, error: null };
  } catch (e) {
    const msg =
      e?.name === "AbortError" ? "AI_TIMEOUT" : e?.message || "AI_NETWORK_ERROR";
    if (DEBUG) console.warn("[aiVideoStatus] exception:", redact(msg));
    return {
      ok: false,
      status: e?.name === "AbortError" ? 408 : 0,
      json: null,
      text: "",
      error: String(msg),
    };
  } finally {
    clear();
  }
}

export async function aiChainGptChat(cfg, { mode = "web3", question, meta } = {}, opts = {}) {
  const m = web3Mode(cfg);
  if (m === "off") return notConfigured("WEB3_DISABLED (WEB3_CHAT_MODE=off)");

  // mode: "web3" | "smart_contract_generator" | "smart_contract_auditor"
  return aiCall(
    cfg,
    "/chaingpt/chat",
    {
      mode: String(mode || "web3"),
      question: String(question || ""),
      meta: meta || undefined,
    },
    opts
  );
}

export async function aiChainGptNews(cfg, { limit = 5 } = {}, opts = {}) {
  const m = web3Mode(cfg);
  if (m === "off") return notConfigured("WEB3_DISABLED (WEB3_CHAT_MODE=off)");
  const q = Number(limit || 5);
  const lim = Number.isFinite(q) ? Math.max(1, Math.min(q, 20)) : 5;
  return aiGet(cfg, "/chaingpt/news?limit=" + encodeURIComponent(String(lim)), opts);
}

export async function aiChainGptNftImage(
  cfg,
  { prompt, model = "velogen", steps = 2, width = 512, height = 512, enhance = "1x", meta } = {},
  opts = {}
) {
  const m = web3Mode(cfg);
  if (m === "off") return notConfigured("WEB3_DISABLED (WEB3_CHAT_MODE=off)");

  return aiCall(
    cfg,
    "/chaingpt/nft/image",
    {
      prompt: String(prompt || ""),
      model: String(model || "velogen"),
      steps: Number(steps || 2),
      width: Number(width || 512),
      height: Number(height || 512),
      enhance: String(enhance || "1x"),
      meta: meta || undefined,
    },
    opts
  );
}

// Convenience: auto-route to ChainGPT if it looks web3, else normal aiChat()
export async function aiSmartChat(cfg, userText, { system = "", meta = {}, retries = 1 } = {}) {
  const m = web3Mode(cfg);

  // Forced modes
  if (m === "on") {
    return aiChainGptChat(
      cfg,
      { mode: "web3", question: String(userText || ""), meta },
      { retries }
    );
  }
  if (m === "off") {
    return aiChat(cfg, String(userText || ""), {
      system: system || "You are a helpful assistant.",
      meta,
      retries,
    });
  }

  // AUTO mode: AI decides route
  const route = await routeChat(cfg, userText, system);

  if (route === "web3") {
    return aiChainGptChat(
      cfg,
      { mode: "web3", question: String(userText || ""), meta },
      { retries }
    );
  }

  return aiChat(cfg, String(userText || ""), {
    system: system || "You are a helpful assistant.",
    meta,
    retries,
  });
}

