      import { getDb } from "./db.js";

const COL = "memory_messages";

export async function addTurn({ mongoUri, platform, userId, chatId, role, text }) {
  const db = await getDb(mongoUri);
  const doc = {
    platform,
    userId: String(userId),
    chatId: chatId ? String(chatId) : "",
    role,
    text: String(text || "").slice(0, 4000),
    ts: new Date(),
  };

  if (!db) return; // allow bot to run without DB
  await db.collection(COL).insertOne(doc);
}

export async function getRecentTurns({ mongoUri, platform, userId, chatId, limit = 14 }) {
  const db = await getDb(mongoUri);
  if (!db) return [];

  const q = {
    platform,
    userId: String(userId),
  };
  if (chatId) q.chatId = String(chatId);

  const rows = await db
    .collection(COL)
    .find(q)
    .sort({ ts: -1 })
    .limit(limit)
    .toArray();

  // return chronological
  return rows.reverse().map((r) => ({ role: r.role, text: r.text }));
}

export async function clearUserMemory({ mongoUri, platform, userId, chatId }) {
  const db = await getDb(mongoUri);
  if (!db) return;

  const q = { platform, userId: String(userId) };
  if (chatId) q.chatId = String(chatId);

  await db.collection(COL).deleteMany(q);
}

rateLimit.js.content:
const buckets = new Map();

export function checkRateLimit(key, { capacity = 6, refillMs = 60_000 } = {}) {
  const now = Date.now();
  const b = buckets.get(key) || { tokens: capacity, ref: now };

  const refill = Math.floor((now - b.ref) / refillMs);
  if (refill > 0) {
    b.tokens = Math.min(capacity, b.tokens + refill);
    b.ref = now;
  }

  if (b.tokens <= 0) {
    buckets.set(key, b);
    return false;
  }

  b.tokens -= 1;
  buckets.set(key, b);

  // bounded map growth
  if (buckets.size > 5000) {
    // delete an arbitrary (oldest not tracked) key to avoid unbounded memory
    const firstKey = buckets.keys().next().value;
    if (firstKey) buckets.delete(firstKey);
  }

  return true;
}

