  const cfg = {
    NODE_ENV: String(env.NODE_ENV || "development"),
    PORT: toInt(env.PORT, 3000),

    TELEGRAM_BOT_TOKEN: String(env.TELEGRAM_BOT_TOKEN || ""),

    // Optional
    TELEGRAM_WEBHOOK_URL: String(env.TELEGRAM_WEBHOOK_URL || ""),

