    RATE_LIMIT_TIKTOK_PER_MIN: toInt(env.RATE_LIMIT_TIKTOK_PER_MIN, 6),

    // Downloader gateway (optional)
    MEDIA_DOWNLOAD_ENDPOINT: String(env.MEDIA_DOWNLOAD_ENDPOINT || ""),
    MEDIA_DOWNLOAD_KEY: String(env.MEDIA_DOWNLOAD_KEY || ""),

    // Network tuning
